// src/pages/RiderLogin.jsx
import React, { useState } from "react";
import { Container, Paper, Typography, TextField, Button, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, checkRiderApproval } from "../services/api";

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleSendOtp = async () => {
    setError(""); setSuccess(""); setLoading(true);
    try {
      // Check if rider is approved
      const approvalRes = await checkRiderApproval(mobile);
      if (!approvalRes.data.success || approvalRes.data.approvalStatus !== "approved") {
        setError("Your account is pending admin approval. Please wait.");
        setLoading(false);
        return;
      }

      // Send OTP
      const res = await sendOtp(mobile, "rider");
      if (res.data.success) {
        setOtpSent(true);
        setSuccess("OTP sent! Check your mobile.");
      }
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setError(""); setSuccess(""); setLoading(true);
    try {
      const res = await sendOtp.verifyOtp(mobile, otp, "rider");
      if (res.data.success) {
        // Save token and role
        localStorage.setItem("token", res.data.data.token);
        localStorage.setItem("role", "rider");
        setSuccess("Login successful! Redirecting...");
        setTimeout(() => navigate("/rider-dashboard"), 1500);
      }
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Invalid OTP or Server error.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>Rider Login</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        {!otpSent ? (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
              margin="normal"
              inputProps={{ maxLength: 10 }}
              required
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "black" }}
              onClick={handleSendOtp}
              disabled={loading || !mobile}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          </>
        ) : (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              margin="normal"
              inputProps={{ maxLength: 6 }}
              required
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "black" }}
              onClick={handleVerifyOtp}
              disabled={loading || !otp}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Typography sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>
            Register
          </Button>
        </Typography>
        <Typography>
          Login as User?{" "}
          <Button onClick={() => navigate("/login")} sx={{ fontWeight: "bold" }}>
            User Login
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
